import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { useLanguage } from '../App';   // ✅ contexte global
import s from './Chat.module.css';

const api = axios.create({
  baseURL: 'http://localhost:8000',
  headers: { 'Content-Type': 'application/json' }
});

api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
  },
  (error) => Promise.reject(error)
);

// ── Translations ───────────────────────────────────────────
const T = {
  fr: {
    newChat: 'Nouveau chat', today: "Aujourd'hui", days30: '30 derniers jours',
    settings: 'Paramètres', signOut: 'Déconnexion',
    welcomeSub: 'Votre assistant intelligent pour la langue et la culture amazighe.',
    placeholder: 'Pose ta question en amazigh, français ou darija...',
    hint: 'Entrée pour envoyer · Shift+Entrée pour nouvelle ligne',
    selectDomain: 'Choisis un domaine pour commencer',
    domainLabel: 'Domaine actif',
    changeDomain: 'Changer',

  },
  en: {
    newChat: 'New chat', today: 'Today', days30: '30 days',
    settings: 'Settings', signOut: 'Sign out',
    welcomeSub: 'Your smart assistant for the Amazigh language and culture.',
    placeholder: 'Ask in Amazigh, French or Darija...',
    hint: 'Enter to send · Shift+Enter for new line',
    selectDomain: 'Choose a domain to get started',
    domainLabel: 'Active domain',
    changeDomain: 'Change',

  },
  ar: {
    newChat: 'محادثة جديدة', today: 'اليوم', days30: 'آخر 30 يومًا',
    settings: 'الإعدادات', signOut: 'تسجيل الخروج',
    welcomeSub: 'مساعدك الذكي للغة والثقافة الأمازيغية.',
    placeholder: 'اسأل بالأمازيغية أو الفرنسية أو الدارجة...',
    hint: 'Enter للإرسال · Shift+Enter لسطر جديد',
    selectDomain: 'اختر مجالاً للبدء',
    domainLabel: 'المجال النشط',
    changeDomain: 'تغيير',

  },
};

// ── 6 Domains ──────────────────────────────────────────────
const DOMAINS = {
  fr: [
    { id: 'health',    label: 'Santé',       desc: 'Vocabulaire médical amazigh' },
    { id: 'economy',   label: 'Économie',    desc: 'Commerce et finances en amazigh' },
    { id: 'education', label: 'Éducation',   desc: 'Apprentissage et enseignement' },
    { id: 'culture',   label: 'Culture',     desc: 'Traditions et patrimoine amazigh' },
    { id: 'tech',      label: 'Technologie', desc: 'Terminologie tech en tamazight' },
    { id: 'daily',     label: 'Quotidien',   desc: 'Conversations de tous les jours' },
  ],
  en: [
    { id: 'health',    label: 'Health',      desc: 'Medical vocabulary in Amazigh' },
    { id: 'economy',   label: 'Economy',     desc: 'Commerce and finance in Amazigh' },
    { id: 'education', label: 'Education',   desc: 'Learning and teaching' },
    { id: 'culture',   label: 'Culture',     desc: 'Amazigh traditions and heritage' },
    { id: 'tech',      label: 'Technology',  desc: 'Tech terminology in Tamazight' },
    { id: 'daily',     label: 'Daily life',  desc: 'Everyday conversations' },
  ],
  ar: [
    { id: 'health',    label: 'الصحة',           desc: 'المفردات الطبية بالأمازيغية' },
    { id: 'economy',   label: 'الاقتصاد',        desc: 'التجارة والمالية بالأمازيغية' },
    { id: 'education', label: 'التعليم',          desc: 'التعلم والتدريس' },
    { id: 'culture',   label: 'الثقافة',          desc: 'التقاليد والتراث الأمازيغي' },
    { id: 'tech',      label: 'التكنولوجيا',      desc: 'المصطلحات التقنية بالتامازيغت' },
    { id: 'daily',     label: 'الحياة اليومية',   desc: 'محادثات يومية' },
  ],
};

export default function Chat() {
  const { user, logout } = useAuth();
  const nav = useNavigate();

  // ✅ Langue depuis le contexte global — pas de state local, pas de boutons ici
  const { language } = useLanguage();

  const [showSettings, setShowSettings] = useState(false);
  const [conversations, setConversations] = useState([]);
  const [activeConvId, setActiveConvId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [activeDomain, setActiveDomain] = useState(null);
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);

  const t = T[language];
  const domains = DOMAINS[language];

  // ✅ Correction du nom affiché : utilise username en priorité, sinon partie avant @,
  //    jamais "Guest" si l'utilisateur est connecté
  const displayName = (() => {
    if (!user) return 'Guest';
    if (user.username && user.username.trim()) return user.username.trim();
    if (user.name && user.name.trim()) return user.name.trim();
    if (user.email) return user.email.split('@')[0];
    return 'Utilisateur';
  })();

  const getGreeting = () => {
    const h = new Date().getHours();
    if (h < 12) return language === 'fr' ? 'Bonjour' : language === 'ar' ? 'صباح الخير' : 'Good morning';
    if (h < 18) return language === 'fr' ? 'Bon après-midi' : language === 'ar' ? 'مساء الخير' : 'Good afternoon';
    return language === 'fr' ? 'Bonsoir' : language === 'ar' ? 'مساء الخير' : 'Good evening';
  };

  useEffect(() => { loadConversations(); }, []);
  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, loading]);

  const loadConversations = async () => {
    try {
      const r = await api.get('/conversations');
      setConversations(r.data.conversations || []);
    } catch (err) { console.error(err); }
  };

  const loadConversation = async (convId) => {
    try {
      const r = await api.get(`/conversations/${convId}/messages`);
      setMessages(r.data.messages.map(m => ({ role: m.sender === 'user' ? 'user' : 'bot', content: m.content })));
      setActiveConvId(convId);
    } catch (err) { console.error(err); }
  };

  const deleteConversation = async (id, e) => {
    e.stopPropagation();
    try {
      await api.delete(`/conversations/${id}`);
      setConversations(prev => prev.filter(c => c.id !== id));
      if (activeConvId === id) { setActiveConvId(null); setMessages([]); }
    } catch (err) { console.error(err); }
  };

  const newConversation = () => {
    setActiveConvId(null);
    setMessages([]);
    setActiveDomain(null);
    textareaRef.current?.focus();
  };

  const handleInputChange = e => {
    setInput(e.target.value);
    e.target.style.height = 'auto';
    e.target.style.height = Math.min(e.target.scrollHeight, 200) + 'px';
  };

  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;

    const domainPrefix = activeDomain ? `domain:${activeDomain} ` : '';
    const fullMessage = domainPrefix + text;

    setMessages(prev => [...prev, { role: 'user', content: text }]);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
    setLoading(true);
    try {
      const r = await api.post('/chat', { message: fullMessage, conversation_id: activeConvId });
      setMessages(prev => [...prev, { role: 'bot', content: r.data.response }]);
      if (!activeConvId && r.data.conversation_id) {
        setActiveConvId(r.data.conversation_id);
        loadConversations();
      }
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'bot', content: 'Erreur de connexion. Veuillez réessayer.' }]);
    } finally { setLoading(false); }
  }, [input, loading, activeConvId, activeDomain]);

  const now = new Date();
  const grouped = conversations.reduce((acc, c) => {
    const d = new Date(c.updated_at || c.created_at);
    const diff = (now - d) / 86400000;
    if (diff < 1) acc.today.push(c);
    else if (diff < 30) acc.days30.push(c);
    return acc;
  }, { today: [], days30: [] });

  const activeDomainObj = domains.find(d => d.id === activeDomain);

  return (
    <div className={s.layout}>

      {/* Settings Modal */}
      {showSettings && (
        <div className={s.modalOverlay} onClick={() => setShowSettings(false)}>
          <div className={s.modal} onClick={e => e.stopPropagation()}>
            <div className={s.modalHeader}>
              <h3>{t.settings}</h3>
              <button className={s.closeModal} onClick={() => setShowSettings(false)}>×</button>
            </div>
            <div className={s.modalBody}>
              <p style={{ fontSize: 13, color: '#6b7280' }}>
                {language === 'fr'
                  ? 'La langue est définie depuis la page d\'accueil.'
                  : language === 'ar'
                  ? 'يتم تحديد اللغة من الصفحة الرئيسية.'
                  : 'Language is set from the home page.'}
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`${s.sidebar} ${sidebarOpen ? s.sideOpen : ''}`}>
        <div className={s.sideHeader}>
          <button className={s.newChatBtn} onClick={newConversation}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" />
            </svg>
            {t.newChat}
          </button>
        </div>

        <div className={s.sideContent}>
          {grouped.today.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.today}</div>
              {grouped.today.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <svg className={s.convIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                  </svg>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} className={s.delBtn}>×</button>
                </div>
              ))}
            </div>
          )}
          {grouped.days30.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.days30}</div>
              {grouped.days30.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <svg className={s.convIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                  </svg>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} className={s.delBtn}>×</button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className={s.sideFooter}>
          {/* ✅ Affiche le vrai nom ou l'email — jamais "Guest" si connecté */}
          <button className={s.userBtn}>
            <div className={s.userAvatar}>{displayName[0]?.toUpperCase()}</div>
            <div className={s.userInfo}>
              <div className={s.userName}>{displayName}</div>
              <div className={s.userEmail}>{user?.email || ''}</div>
            </div>
          </button>
          <button className={s.signOutBtn} onClick={() => { logout(); nav('/'); }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4" />
              <polyline points="16 17 21 12 16 7" />
              <line x1="21" y1="12" x2="9" y2="12" />
            </svg>
            {t.signOut}
          </button>
        </div>
      </aside>

      {/* Main */}
      <main className={s.main}>
        <div className={s.mainHeader}>
          <div className={s.headerLeft}>
            <button className={s.menuBtn} onClick={() => setSidebarOpen(v => !v)}>☰</button>
            <div className={s.headerLogo}>
              <img src="/logo.png" alt="Logo" width={26} />
              <span>AWAL GPT</span>
            </div>
            {/* Active domain badge */}
            {activeDomainObj && (
              <div className={s.headerDomainBadge}>
                <span>{activeDomainObj.label}</span>
                <button onClick={() => setActiveDomain(null)}>×</button>
              </div>
            )}
          </div>
          {/* ✅ SUPPRIMÉ : les boutons FR/EN/AR n'apparaissent plus ici */}
          <div className={s.headerActions}>
            {/* vide intentionnellement — langue gérée depuis la Landing */}
          </div>
        </div>

        <div className={s.messagesArea}>
          <div className={s.messages}>
            {messages.length === 0 ? (
              <div className={s.welcome}>
                <div className={s.greetingRow}>
                  <span className={s.asterisk}>
                    <img src="/logo.png" alt="Logo" className={s.welcomeLogo} />
                  </span>
                  <h1 className={s.welcomeTitle}>
                    {getGreeting()}, <span className={s.greetingName}>{displayName}</span>
                  </h1>
                </div>
                <p className={s.welcomeSub}>{t.welcomeSub}</p>

                {/* Domain selector */}
                {!activeDomain ? (
                  <div className={s.domainSection}>
                    <p className={s.domainSectionLabel}>{t.selectDomain}</p>
                    <div className={s.domainGrid}>
                      {domains.map(d => (
                        <button
                          key={d.id}
                          className={s.domainCard}
                          onClick={() => setActiveDomain(d.id)}
                        >
                          <span className={s.domainCardLabel}>{d.label}</span>
                          <span className={s.domainCardDesc}>{d.desc}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                ) : (
                  <div className={s.activeDomainWelcome}>
                    <div>
                      <div className={s.activeDomainName}>{activeDomainObj?.label}</div>
                      <div className={s.activeDomainDesc}>{activeDomainObj?.desc}</div>
                    </div>
                    <button className={s.changeDomainBtn} onClick={() => setActiveDomain(null)}>
                      {t.changeDomain}
                    </button>
                  </div>
                )}

                {/* Info cards */}
                <div className={s.welcomeGrid}>
                  <div className={s.welcomeCard}>
                    <h4>{t.examples}</h4>
                    {[t.ex1, t.ex2, t.ex3].map((ex, i) => (
                      <p key={i} onClick={() => setInput(ex)} style={{ cursor: 'pointer' }}>{ex}</p>
                    ))}
                  </div>
                  <div className={s.welcomeCard}>
                    <h4>{t.capabilities}</h4>
                    {[t.cap1, t.cap2, t.cap3].map((c, i) => (
                      <p key={i} className={s.capability}>{c}</p>
                    ))}
                  </div>
                  <div className={s.welcomeCard}>
                    <h4>{t.limitations}</h4>
                    {[t.lim1, t.lim2, t.lim3].map((l, i) => (
                      <p key={i} className={s.limitation}>{l}</p>
                    ))}
                  </div>
                </div>
              </div>
            ) : (
              messages.map((msg, idx) => (
                <div key={idx} className={`${s.message} ${msg.role === 'user' ? s.messageUser : s.messageBot}`}>
                  <div className={s.messageAvatar}>
                    {msg.role === 'user' ? (
                      <div className={s.userAvatarMsg}>{displayName[0]?.toUpperCase()}</div>
                    ) : (
                      <div className={s.botAvatar}>A</div>
                    )}
                  </div>
                  <div className={s.messageContent}>
                    <div className={s.messageName}>
                      {msg.role === 'user' ? displayName : 'AWAL GPT'}
                      {msg.role === 'user' && activeDomainObj && (
                        <span className={s.msgDomainTag}>{activeDomainObj.label}</span>
                      )}
                    </div>
                    <div className={s.messageText}>{msg.content}</div>
                  </div>
                </div>
              ))
            )}
            {loading && (
              <div className={`${s.message} ${s.messageBot}`}>
                <div className={s.messageAvatar}>
                  <div className={s.botAvatar}>A</div>
                </div>
                <div className={s.messageContent}>
                  <div className={s.messageName}>AWAL GPT</div>
                  <div className={s.typing}><span /><span /><span /></div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        </div>

        {/* Input area */}
        <div className={s.inputArea}>
          <div className={s.inputContainer}>
            {activeDomainObj && (
              <div className={s.inputDomainBar}>
                <span className={s.inputDomainLabel}>{activeDomainObj.label}</span>
                <span className={s.inputDomainAuto}>
                  {language === 'fr' ? '— préfixé automatiquement' : language === 'ar' ? '— يُضاف تلقائيًا' : '— auto-prefixed'}
                </span>
                <button className={s.inputDomainClose} onClick={() => setActiveDomain(null)}>×</button>
              </div>
            )}
            <div className={s.inputBox}>
              <textarea
                ref={textareaRef}
                className={s.textarea}
                placeholder={t.placeholder}
                value={input}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                rows={1}
                disabled={loading}
              />
              <button className={s.sendBtn} onClick={sendMessage} disabled={loading || !input.trim()}>
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <line x1="22" y1="2" x2="11" y2="13" />
                  <polygon points="22 2 15 22 11 13 2 9 22 2" />
                </svg>
              </button>
            </div>
            <div className={s.inputHint}>{t.hint}</div>
          </div>
        </div>
      </main>
    </div>
  );
}
